import{_ as a,o as t,c as i,a2 as r}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"Architecture Decisions","description":"","frontmatter":{},"headers":[],"relativePath":"reference/architecture-decisions.md","filePath":"reference/architecture-decisions.md","lastUpdated":null}'),n={name:"reference/architecture-decisions.md"};function o(d,e,s,c,l,u){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="architecture-decisions" tabindex="-1">Architecture Decisions <a class="header-anchor" href="#architecture-decisions" aria-label="Permalink to &quot;Architecture Decisions&quot;">​</a></h1><p>Architecture decision records live under <code>docs/decisions</code> in the repository. This page summarizes the current reader-facing decisions.</p><h2 id="adr-002-bpmn-centric-autofac-runtime-by-default" tabindex="-1">ADR-002: BPMN-centric Autofac runtime by default <a class="header-anchor" href="#adr-002-bpmn-centric-autofac-runtime-by-default" aria-label="Permalink to &quot;ADR-002: BPMN-centric Autofac runtime by default&quot;">​</a></h2><p>Autofac&#39;s default workflow runtime is the in-process, Postgres-backed Autofac runtime. It avoids requiring Camunda for the open-source path and keeps the default deployment simpler.</p><p>Operational impact:</p><ul><li><code>WorkflowRuntime:Mode=Autofac</code> is the default.</li><li>Camunda options should not be read unless <code>WorkflowRuntime:Mode=Camunda</code>.</li><li>Health endpoints expose the active runtime mode.</li></ul><h2 id="adr-001-camunda-8-for-production-bpmn-runtime" tabindex="-1">ADR-001: Camunda 8 for production BPMN runtime <a class="header-anchor" href="#adr-001-camunda-8-for-production-bpmn-runtime" aria-label="Permalink to &quot;ADR-001: Camunda 8 for production BPMN runtime&quot;">​</a></h2><p>This decision is superseded by ADR-002 for the default runtime. Camunda remains an opt-in enterprise adapter.</p><p>Operational impact:</p><ul><li>Existing Camunda documentation should be read as adapter-specific.</li><li>New quickstart and open-core docs should assume the Autofac runtime unless explicitly stated otherwise.</li></ul><h2 id="adr-003-opensandbox-control-plane-with-kata-runtime" tabindex="-1">ADR-003: OpenSandbox control plane with Kata runtime <a class="header-anchor" href="#adr-003-opensandbox-control-plane-with-kata-runtime" aria-label="Permalink to &quot;ADR-003: OpenSandbox control plane with Kata runtime&quot;">​</a></h2><p>OpenSandbox/Kata is the preferred path for stronger sandbox isolation where plain Docker boundaries are not enough.</p><p>Operational impact:</p><ul><li>Docker is useful for local development and simple installs.</li><li>Production environments with stricter egress or isolation requirements should evaluate OpenSandbox or Kubernetes-backed sandboxing.</li><li>Workflow authors should still express intent through <code>sandboxProfile</code>.</li></ul><h2 id="when-to-add-an-adr" tabindex="-1">When to add an ADR <a class="header-anchor" href="#when-to-add-an-adr" aria-label="Permalink to &quot;When to add an ADR&quot;">​</a></h2><p>Add or update an ADR when a change:</p><ul><li>changes a public runtime mode</li><li>changes a security boundary</li><li>changes the deployment model</li><li>changes data residency expectations</li><li>deprecates or supersedes an integration/runtime</li><li>introduces a lasting architectural tradeoff</li></ul>',17)])])}const m=a(n,[["render",o]]);export{h as __pageData,m as default};
